-- ============================================
-- Legislacao full-site: marconi-perillo / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2007-2010
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/4535/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = marconi-perillo-senado-completo-autoria-substantiva-2007-2010-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2007_2010_20260506
--
-- Filtro factual: endpoint senador/4535/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=4535
--   com NumOrdemAutor=1. Resultado deste snapshot: 77 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'marconi-perillo';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'marconi-perillo: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'marconi-perillo-senado-completo-autoria-substantiva-2007-2010-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('79964', '80377', '80133', '80291', '80362', '80379', '80388', '81534', '81817', '82080', '82083', '82086', '82090', '82089', '82091', '82092', '82189', '82228', '82299', '82392', '82604', '82879', '83077', '83076', '83158', '83159', '83160', '83694', '83924', '83944', '84053', '84062', '84282', '84279', '84278', '84397', '84398', '84399', '84401', '84487', '84863', '84860', '85290', '86956', '86955', '86954', '87301', '87344', '87354', '87348', '88059', '88058', '88783', '86335', '90785', '93208', '89679', '90158', '90635', '92012', '93241', '94083', '94381', '96819', '96885', '95517', '95519', '95659', '95873', '95981', '96038', '96273', '96419', '96851', '96926', '97204', '98516');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('79964', '80377', '80133', '80291', '80362', '80379', '80388', '81534', '81817', '82080', '82083', '82086', '82090', '82089', '82091', '82092', '82189', '82228', '82299', '82392', '82604', '82879', '83077', '83076', '83158', '83159', '83160', '83694', '83924', '83944', '84053', '84062', '84282', '84279', '84278', '84397', '84398', '84399', '84401', '84487', '84863', '84860', '85290', '86956', '86955', '86954', '87301', '87344', '87354', '87348', '88059', '88058', '88783', '86335', '90785', '93208', '89679', '90158', '90635', '92012', '93241', '94083', '94381', '96819', '96885', '95517', '95519', '95659', '95873', '95981', '96038', '96273', '96419', '96851', '96926', '97204', '98516')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'marconi-perillo-senado-completo-autoria-substantiva-2007-2010-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao marconi-perillo: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'GO'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2010
    AND COALESCE(hp.periodo_fim, 9999) >= 2007;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao marconi-perillo: mandato Senado/GO 2007-2010 nao encontrado em historico_politico';
  END IF;
END $$;

